	int sum=0;
	scanf("%d%d%d",&a,&b,&c);
	for (x=1; x<=a;x++)
		for (y=1;x*y<=a;y++)
			for(z=1;y*z<=b;z++)
			{
				if (x*y==a&&x*z==c&&y*z==b)
				{
					sum=x+y+z;
					goto out;
				}
			}
	out:
	printf("%d",sum*4);
